\displaystyle{\begin{aligned}
   \frac{7}{10} + \frac{5}{6}
        \amp = \frac{21}{30} + \frac{25}{30} \\
        \amp = \frac{21 + 25}{30} \\
        \amp = \frac{46}{30} \amp \hbox{We can reduce this by dividing 2 into both the numerator and the denominator.
}\\
        \amp = \frac{23}{15}
\end{aligned}
